import React, { useState, useEffect, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import './Dashboard.css';

const API = 'http://localhost:5000';

// ── Helpers ───────────────────────────────────────────────────────────────────
const fmt = (n) =>
  new Intl.NumberFormat('en-IN', { style: 'currency', currency: 'INR', minimumFractionDigits: 2 }).format(n);

const timeAgo = (iso) => {
  const diff = Date.now() - new Date(iso).getTime();
  const m = Math.floor(diff / 60000);
  if (m < 1)  return 'just now';
  if (m < 60) return `${m}m ago`;
  const h = Math.floor(m / 60);
  if (h < 24) return `${h}h ago`;
  return new Date(iso).toLocaleDateString('en-IN', { day: 'numeric', month: 'short' });
};

// ── Add Money Modal ───────────────────────────────────────────────────────────
function AddMoneyModal({ user, onClose, onSuccess }) {
  const [amount, setAmount]   = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError]     = useState('');
  const QUICK = [500, 1000, 2000, 5000];

  const handleAdd = async () => {
    if (!amount || isNaN(amount) || Number(amount) <= 0) {
      setError('Enter a valid amount'); return;
    }
    setLoading(true); setError('');
    try {
      const res  = await fetch(`${API}/api/wallet/add`, {
        method:  'POST',
        headers: { 'Content-Type': 'application/json' },
        body:    JSON.stringify({ user_id: user.id, amount: Number(amount) }),
      });
      const data = await res.json();
      if (!res.ok) { setError(data.error || 'Failed'); return; }
      onSuccess(data.new_balance, data.txn_id);
    } catch { setError('Network error'); }
    finally { setLoading(false); }
  };

  return (
    <div className="modal-overlay" onClick={onClose}>
      <div className="modal-card" onClick={e => e.stopPropagation()}>
        <div className="modal-header">
          <h2>Add Money</h2>
          <button className="modal-close" onClick={onClose}>✕</button>
        </div>
        <div className="modal-body">
          <p className="modal-sub">Current balance: <strong>{fmt(user.balance)}</strong></p>
          <div className="quick-amounts">
            {QUICK.map(q => (
              <button key={q} className={`quick-btn ${amount == q ? 'active' : ''}`}
                onClick={() => setAmount(String(q))}>
                ₹{q.toLocaleString('en-IN')}
              </button>
            ))}
          </div>
          <div className="input-group">
            <span className="input-prefix">₹</span>
            <input
              type="number"
              placeholder="Enter amount"
              value={amount}
              onChange={e => setAmount(e.target.value)}
              className="modal-input"
            />
          </div>
          {error && <p className="modal-error">{error}</p>}
          <button className="modal-btn primary" onClick={handleAdd} disabled={loading}>
            {loading ? 'Processing...' : 'Add Money'}
          </button>
        </div>
      </div>
    </div>
  );
}

// ── Send Money Modal ──────────────────────────────────────────────────────────
function SendMoneyModal({ user, onClose, onSuccess }) {
  const [email,   setEmail]   = useState('');
  const [amount,  setAmount]  = useState('');
  const [note,    setNote]    = useState('');
  const [results, setResults] = useState([]);
  const [selected, setSelected] = useState(null);
  const [loading, setLoading]  = useState(false);
  const [searching, setSearching] = useState(false);
  const [error, setError]      = useState('');

  useEffect(() => {
    if (email.length < 3) { setResults([]); return; }
    const t = setTimeout(async () => {
      setSearching(true);
      try {
        const res  = await fetch(`${API}/api/users/search?email=${encodeURIComponent(email)}`);
        const data = await res.json();
        setResults(data.filter(u => u.id !== user.id));
      } catch {} finally { setSearching(false); }
    }, 400);
    return () => clearTimeout(t);
  }, [email]);

  const handleSend = async () => {
    if (!selected) { setError('Select a recipient'); return; }
    if (!amount || isNaN(amount) || Number(amount) <= 0) { setError('Enter a valid amount'); return; }
    if (Number(amount) > user.balance) { setError('Insufficient balance'); return; }
    setLoading(true); setError('');
    try {
      const res  = await fetch(`${API}/api/wallet/send`, {
        method:  'POST',
        headers: { 'Content-Type': 'application/json' },
        body:    JSON.stringify({
          sender_id: user.id,
          to_email:  selected.email,
          amount:    Number(amount),
          note,
        }),
      });
      const data = await res.json();
      if (!res.ok) { setError(data.error || 'Failed'); return; }
      onSuccess(data.new_balance, data.txn_id, selected.name);
    } catch { setError('Network error'); }
    finally { setLoading(false); }
  };

  return (
    <div className="modal-overlay" onClick={onClose}>
      <div className="modal-card" onClick={e => e.stopPropagation()}>
        <div className="modal-header">
          <h2>Send Money</h2>
          <button className="modal-close" onClick={onClose}>✕</button>
        </div>
        <div className="modal-body">
          <p className="modal-sub">Available: <strong>{fmt(user.balance)}</strong></p>

          {!selected ? (
            <>
              <div className="input-group">
                <input
                  type="email"
                  placeholder="Search by email..."
                  value={email}
                  onChange={e => { setEmail(e.target.value); setSelected(null); }}
                  className="modal-input"
                  autoFocus
                />
              </div>
              {searching && <p className="modal-searching">Searching...</p>}
              {results.length > 0 && (
                <div className="search-results">
                  {results.map(u => (
                    <div key={u.id} className="search-result-item" onClick={() => { setSelected(u); setEmail(u.email); setResults([]); }}>
                      <div className="result-avatar">{u.name[0]}</div>
                      <div>
                        <div className="result-name">{u.name}</div>
                        <div className="result-email">{u.email}</div>
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </>
          ) : (
            <div className="selected-recipient">
              <div className="recipient-avatar">{selected.name[0]}</div>
              <div>
                <div className="recipient-name">{selected.name}</div>
                <div className="recipient-email">{selected.email}</div>
              </div>
              <button className="change-btn" onClick={() => setSelected(null)}>Change</button>
            </div>
          )}

          {selected && (
            <>
              <div className="input-group">
                <span className="input-prefix">₹</span>
                <input
                  type="number"
                  placeholder="Amount"
                  value={amount}
                  onChange={e => setAmount(e.target.value)}
                  className="modal-input"
                  autoFocus
                />
              </div>
              <input
                type="text"
                placeholder="Add a note (optional)"
                value={note}
                onChange={e => setNote(e.target.value)}
                className="modal-input note-input"
              />
            </>
          )}

          {error && <p className="modal-error">{error}</p>}

          {selected && (
            <button className="modal-btn primary" onClick={handleSend} disabled={loading}>
              {loading ? 'Sending...' : `Send ${amount ? fmt(Number(amount)) : 'Money'}`}
            </button>
          )}
        </div>
      </div>
    </div>
  );
}

// ── Toast ─────────────────────────────────────────────────────────────────────
function Toast({ msg, onDone }) {
  useEffect(() => { const t = setTimeout(onDone, 3000); return () => clearTimeout(t); }, []);
  return <div className="toast">{msg}</div>;
}

// ── Main Dashboard ────────────────────────────────────────────────────────────
export default function Dashboard() {
  const { user: authUser, logout } = useAuth();
  const navigate = useNavigate();

  const [user,         setUser]         = useState(authUser);
  const [transactions, setTransactions] = useState([]);
  const [txnLoading,   setTxnLoading]   = useState(true);
  const [modal,        setModal]        = useState(null); // 'add' | 'send' | null
  const [toast,        setToast]        = useState('');
  const [activeTab,    setActiveTab]    = useState('home');

  const loadTransactions = useCallback(async () => {
    if (!user?.id) return;
    setTxnLoading(true);
    try {
      const res  = await fetch(`${API}/api/transactions/${user.id}`);
      const data = await res.json();
      setTransactions(data.transactions || []);
    } catch {} finally { setTxnLoading(false); }
  }, [user?.id]);

  useEffect(() => { loadTransactions(); }, [loadTransactions]);

  const handleAddSuccess = (newBalance, txnId) => {
    setUser(u => ({ ...u, balance: newBalance }));
    setModal(null);
    setToast(`✓ Money added! Txn: ${txnId}`);
    loadTransactions();
  };

  const handleSendSuccess = (newBalance, txnId, recipientName) => {
    setUser(u => ({ ...u, balance: newBalance }));
    setModal(null);
    setToast(`✓ Sent to ${recipientName}! Txn: ${txnId}`);
    loadTransactions();
  };

  const handleLogout = () => { logout(); navigate('/'); };

  // Stats from transactions
  const totalSent     = transactions.filter(t => t.type === 'debit').reduce((s, t) => s + t.amount, 0);
  const totalReceived = transactions.filter(t => t.type === 'credit').reduce((s, t) => s + t.amount, 0);

  return (
    <div className="dash-root">
      {/* ── Sidebar ── */}
      <aside className="dash-sidebar">
        <div className="sidebar-logo">
          <span className="logo-mark">N</span>
          <span className="logo-text">NovaPay</span>
        </div>

        <nav className="sidebar-nav">
          {[
            { id: 'home',  icon: '⬡', label: 'Overview'     },
            { id: 'txns',  icon: '↕', label: 'Transactions'  },
          ].map(item => (
            <button
              key={item.id}
              className={`nav-item ${activeTab === item.id ? 'active' : ''}`}
              onClick={() => setActiveTab(item.id)}
            >
              <span className="nav-icon">{item.icon}</span>
              <span className="nav-label">{item.label}</span>
            </button>
          ))}
        </nav>

        <div className="sidebar-footer">
          <div className="sidebar-user">
            <div className="sidebar-avatar">{user?.name?.[0] || 'U'}</div>
            <div className="sidebar-user-info">
              <div className="sidebar-name">{user?.name}</div>
              <div className="sidebar-email">{user?.email}</div>
            </div>
          </div>
          <button className="logout-btn" onClick={handleLogout}>Sign out</button>
        </div>
      </aside>

      {/* ── Main ── */}
      <main className="dash-main">

        {activeTab === 'home' && (
          <>
            {/* Balance Card */}
            <section className="balance-section">
              <div className="balance-card">
                <div className="balance-card-bg" />
                <div className="balance-top">
                  <div>
                    <p className="balance-label">Total Balance</p>
                    <h1 className="balance-amount">{fmt(user?.balance || 0)}</h1>
                  </div>
                  <div className="account-badge">
                    <span className="acct-label">A/C</span>
                    <span className="acct-no">{user?.account_no || '——'}</span>
                  </div>
                </div>
                <div className="balance-stats">
                  <div className="bstat">
                    <span className="bstat-arrow up">↑</span>
                    <div>
                      <div className="bstat-label">Money In</div>
                      <div className="bstat-val">{fmt(totalReceived)}</div>
                    </div>
                  </div>
                  <div className="bstat-divider" />
                  <div className="bstat">
                    <span className="bstat-arrow down">↓</span>
                    <div>
                      <div className="bstat-label">Money Out</div>
                      <div className="bstat-val">{fmt(totalSent)}</div>
                    </div>
                  </div>
                </div>
              </div>

              {/* Quick Actions */}
              <div className="quick-actions">
                <button className="action-card" onClick={() => setModal('add')}>
                  <div className="action-icon add-icon">+</div>
                  <span>Add Money</span>
                </button>
                <button className="action-card" onClick={() => setModal('send')}>
                  <div className="action-icon send-icon">→</div>
                  <span>Send</span>
                </button>
              </div>
            </section>

            {/* Recent Transactions */}
            <section className="recent-section">
              <div className="section-header">
                <h2 className="section-title">Recent Activity</h2>
                <button className="see-all" onClick={() => setActiveTab('txns')}>See all</button>
              </div>
              <TransactionList transactions={transactions.slice(0, 5)} loading={txnLoading} />
            </section>
          </>
        )}

        {activeTab === 'txns' && (
          <section className="txns-section">
            <div className="section-header">
              <h2 className="section-title">All Transactions</h2>
              <span className="txn-count">{transactions.length} records</span>
            </div>
            <TransactionList transactions={transactions} loading={txnLoading} />
          </section>
        )}
      </main>

      {/* ── Modals ── */}
      {modal === 'add'  && <AddMoneyModal  user={user} onClose={() => setModal(null)} onSuccess={handleAddSuccess}  />}
      {modal === 'send' && <SendMoneyModal user={user} onClose={() => setModal(null)} onSuccess={handleSendSuccess} />}
      {toast && <Toast msg={toast} onDone={() => setToast('')} />}
    </div>
  );
}

// ── Transaction List Component ─────────────────────────────────────────────────
function TransactionList({ transactions, loading }) {
  if (loading) return (
    <div className="txn-loading">
      {[1,2,3].map(i => <div key={i} className="txn-skeleton" />)}
    </div>
  );
  if (!transactions.length) return (
    <div className="txn-empty">
      <p>No transactions yet</p>
      <span>Add money or send to someone to get started</span>
    </div>
  );

  return (
    <div className="txn-list">
      {transactions.map((t, i) => (
        <div key={t._id || i} className={`txn-item ${t.type}`}>
          <div className="txn-icon-wrap">
            <div className={`txn-icon ${t.type}`}>
              {t.type === 'credit' ? '↓' : '↑'}
            </div>
          </div>
          <div className="txn-info">
            <div className="txn-title">
              {t.type === 'credit' ? t.from_name : t.to_name}
            </div>
            <div className="txn-meta">
              <span className="txn-id">{t.txn_id}</span>
              <span className="txn-dot">·</span>
              <span className="txn-time">{timeAgo(t.timestamp)}</span>
            </div>
            {t.note && <div className="txn-note">{t.note}</div>}
          </div>
          <div className={`txn-amount ${t.type}`}>
            {t.type === 'credit' ? '+' : '−'}{fmt(t.amount)}
          </div>
        </div>
      ))}
    </div>
  );
}
